def solve(s: str) -> list[str]:
    segments = []
    seen = set()
    start = 0
    while start < len(s):
        current = ''
        while start < len(s):
            current += s[start]
            if current not in seen:
                seen.add(current)
                segments.append(current)
                break
            else:
                start += 1
        else:
            break
    return segments
